UPDATE parties
SET code = COALESCE(
    customer_code,
    supplier_code,
    'PRT-' || substr(id::text, 1, 8)
);

ALTER TABLE parties DROP CONSTRAINT IF EXISTS ck_parties_customer_code_role;
ALTER TABLE parties DROP CONSTRAINT IF EXISTS ck_parties_supplier_code_role;
DROP INDEX IF EXISTS uk_parties_tenant_customer_code;
DROP INDEX IF EXISTS uk_parties_tenant_supplier_code;
